sys_variable_value.value:
(function (outputs, steps, params, stepResult, assertEqual) {

	var bLog = false;
	var _gtCache = new global.GlobalToolsCache();

	var _gtATF = new global.GlobalToolsATF('GlobalToolsCache', _gtCache, bLog, outputs, steps, params, stepResult, assertEqual);

	// Test the 3 types of cache types

	_gtATF.runATF('setValue', undefined, '', 'sugus');
	_gtATF.runATF('setValue', undefined, 'gtc/atf/test1', '');
	_gtATF.runATF('setValue', undefined, 'gtc/atf/test2', 'gugus');
	
	_gtATF.runATF('getValue', undefined, '');
	_gtATF.runATF('getValue', undefined, 'gtc/atf/test');
	_gtATF.runATF('getValue', 'gugus', 'gtc/atf/test2');

	_gtATF.runATF('checkValue', false, '');
	_gtATF.runATF('checkValue', false, 'gtc/atf/test');
	_gtATF.runATF('checkValue', true, 'gtc/atf/test2');

	_gtATF.runATF('clearValue', undefined, 'gtc/atf/test2');

	_gtATF.runATF('getValue', undefined, 'gtc/atf/test2');
	
	_gtATF.runATF('setValue', undefined, 'gtc/atf/test3', 'gugus', 'glidecontroller');
	
	_gtATF.runATF('getValue', 'gugus', 'gtc/atf/test3', 'glidecontroller');

	_gtATF.runATF('checkValue', false, 'gtc/atf/test', 'glidecontroller');
	_gtATF.runATF('checkValue', true, 'gtc/atf/test3', 'glidecontroller');

	_gtATF.runATF('clearValue', undefined, 'gtc/atf/test3', 'glidecontroller');

	_gtATF.runATF('getValue', undefined, 'gtc/atf/test3', 'glidecontroller');

	_gtATF.runATF('setValue', undefined, 'gtc/atf/test3', 'gugus', 'session');
	
	_gtATF.runATF('getValue', 'gugus', 'gtc/atf/test3', 'session');

	_gtATF.runATF('checkValue', false, 'gtc/atf/test', 'session');
	_gtATF.runATF('checkValue', true, 'gtc/atf/test3', 'session');

	_gtATF.runATF('clearValue', undefined, 'gtc/atf/test3', 'session');

	_gtATF.runATF('getValue', undefined, 'gtc/atf/test3', 'session');

	// Test the transaction cache only functions

	_gtATF.runATF('setValue', undefined, 'gtc/atf/test4', 'gugus');
	
	_gtATF.runATF('getValue', 'gugus', 'gtc/atf/test4');

	_gtATF.runATF('getCache', '{"gtc":{"atf":{"test4":"gugus"}}}', 'gtc/atf/test4');
	_gtATF.runATF('getCache', '{"gtc":{"atf":{"test4":"gugus"}}}', 'gtc/atf/test4', true);
	
	_gtATF.runATF('resetCache', undefined);

	_gtATF.runATF('getValue', undefined, 'gtc/atf/test4');

	_gtATF.runATF('checkValue', false, 'gtc/atf/test4');
	_gtATF.runATF('getCache', '{}', true);
	
	return _gtATF.endATF();

})(outputs, steps, params, stepResult, assertEqual);
